```jsx
import { Link, useNavigate } from 'react-router-dom';

const PrefetchLink = ({ to, children, ...props }) => {
  const navigate = useNavigate();

  const handlePrefetch = () => {
    // Préchargement du composant via React.lazy
    const Component = lazy(() => import(`../pages${to}/index.jsx`));
    // Déclenche le chargement du bundle
    Component.preload?.();

    // Alternative avec React Router (v6.4+) : 
    // navigate(to, { unstable_prefetch: true });
  };

  return (
    <Link to={to} onMouseEnter={handlePrefetch} {...props}>
      {children}
    </Link>
  );
};
